import { assignInlineVars } from '@vanilla-extract/dynamic';
import clsx from 'clsx';

import {
  headerContainer,
  headerSubText,
  headerText,
  headerTextMultiLine,
  headerWidthVar,
  maxLinesVar,
} from './Header.sty.js';
import { HeaderProps, HeaderValueFormatter } from './types/header.js';
import { getShowRangeDuration } from './utils/get-show-range-duration.js';
import { isHeaderEmpty } from './utils/type-guards.js';
import { defaultLabelFormatterStrategy } from './utils/value-formatters.js';
import { Divider } from '../../../../../../layouts/divider/Divider.js';
import { Tooltip } from '../../../../../../overlays/tooltip/Tooltip.js';
import {
  DEFAULT_HEADER_LINES,
  DEFAULT_TRUNCATION_MODE,
  MAX_HEADER_LINES,
  TOOLTIP_WRAPPER_PADDING,
} from '../../constants.js';
import { useExternalConfig } from '../../contexts/ExternalConfigContext.js';
import { useTooltipDimensions } from '../../contexts/TooltipDimensionsContext.js';
import { useDefaultConfig } from '../../hooks/useDefaultConfig.js';
import { useDefaultLabels } from '../../hooks/useDefaultLabels.js';
import { divider, TOOLTIP_MAX_WIDTH } from '../../tooltip.sty.js';
import { computeHeaderDisplay } from './utils/compute-header-display.js';
import { computeSubheaderDisplay } from './utils/compute-subheader-display.js';
import { getNonGeometryHeader } from './utils/get-non-geometry-header.js';

/** @public */
export const Header = (props: HeaderProps) => {
  const {
    header1,
    header2,
    subheader,
    label,
    label2,
    maxLines,
    duration1,
    duration2,
    showRangeDuration2,
  } = props;
  const labelFor = useDefaultLabels();
  const defaultConfig = useDefaultConfig();
  const defaultStrategy = (defaultConfig?.headerFormatStrategy ??
    defaultLabelFormatterStrategy) as HeaderValueFormatter;
  const { displayHeaderDivider, truncationMode = DEFAULT_TRUNCATION_MODE } =
    useExternalConfig();
  const containerWidth = useTooltipDimensions()?.width || TOOLTIP_MAX_WIDTH;
  const showedLines = Math.min(
    maxLines ?? DEFAULT_HEADER_LINES,
    MAX_HEADER_LINES,
  );
  const isSingleLine = showedLines === 1;
  const isTruncationEnd = truncationMode === 'end';

  const showRangeDuration1 = getShowRangeDuration(
    defaultConfig,
    props.showRangeDuration1,
  );
  const computedShowDuration2 = showRangeDuration2 ?? false;
  const formatStrategy = defaultStrategy ?? getNonGeometryHeader(header1);
  const header2FormatStrategy = getNonGeometryHeader(header2);
  const availableWidth = containerWidth - TOOLTIP_WRAPPER_PADDING * 2;

  if (isHeaderEmpty(header1, header2, subheader)) {
    return null;
  }

  const sharedDisplayParams = {
    labelFor,
    isSingleLine,
    isTruncationEnd,
    availableWidth,
    showedLines,
    truncationMode,
    showRangeDuration: showRangeDuration1,
  };

  const {
    content: headerContent,
    totalTextWidth,
    shownText,
    isTruncated,
    durationContent,
    durationSuffix,
  } = computeHeaderDisplay({
    header: header1,
    label,
    duration: duration1,
    formatStrategy,
    ...sharedDisplayParams,
  });

  const {
    content: header2Content,
    totalTextWidth: header2TotalTextWidth,
    shownText: shownHeader2Text,
    isTruncated: isHeader2Truncated,
    durationContent: duration2Content,
    durationSuffix: duration2Suffix,
  } = computeHeaderDisplay({
    header: header2,
    label: label2,
    duration: duration2,
    formatStrategy: header2FormatStrategy,
    ...sharedDisplayParams,
    showRangeDuration: computedShowDuration2,
  });

  const { subheaderContent, shownSubheaderText, isSubheaderTruncated } =
    computeSubheaderDisplay({
      subheader,
      formatStrategy,
      availableWidth,
      truncationMode,
    });

  const headerClassName =
    !isSingleLine && isTruncationEnd
      ? clsx(headerText, headerTextMultiLine)
      : headerText;

  const shouldConstrainWidth =
    totalTextWidth > availableWidth || header2TotalTextWidth > availableWidth;
  const headerContainerStyle = shouldConstrainWidth
    ? assignInlineVars({ [headerWidthVar]: `${availableWidth}px` })
    : {};
  const isHeader2Unique =
    header2Content + duration2Suffix !== headerContent + durationSuffix;

  return (
    <>
      <div className={headerContainer} style={headerContainerStyle}>
        <Tooltip text={headerContent} disabled={!isTruncated}>
          <p
            className={headerClassName}
            style={assignInlineVars({ [maxLinesVar]: String(showedLines) })}
          >
            {shownText}
            {durationContent && durationContent !== '0' && (
              <span className={headerSubText}>{durationSuffix}</span>
            )}
          </p>
        </Tooltip>
        {shownHeader2Text && isHeader2Unique && (
          <div>
            <Tooltip text={header2Content} disabled={!isHeader2Truncated}>
              <p
                className={headerClassName}
                style={assignInlineVars({
                  [maxLinesVar]: String(showedLines),
                })}
              >
                {shownHeader2Text}
                {duration2Content && duration2Content !== '0' && (
                  <span className={headerSubText}>{duration2Suffix}</span>
                )}
              </p>
            </Tooltip>
          </div>
        )}
        {shownSubheaderText && (
          <div>
            <Tooltip text={subheaderContent} disabled={!isSubheaderTruncated}>
              <p className={headerSubText}>{shownSubheaderText}</p>
            </Tooltip>
          </div>
        )}
      </div>
      {displayHeaderDivider && (
        <Divider orientation="horizontal" key="divider" className={divider} />
      )}
    </>
  );
};
